// famililook-shared/src/rewards/useVariableReward.js
// Session-scoped rare stat injection. Product-aware rarity labels.
// Never same stat type twice in a row within a session.

import { useMemo } from 'react'
import { RARITY_LABELS } from './StatHighlight.jsx'

const SESSION_KEY = 'fl:lastRewardStat'

// Rarity tiers mapped to score thresholds (0-1 scale)
// These are heuristic thresholds pending real population data from desktop3.
// When rarityThresholds.json is extracted from calibration data, replace these.
const RARITY_THRESHOLDS = [
  { min: 0.99, tier: 'mythic' },
  { min: 0.97, tier: 'legendary' },
  { min: 0.93, tier: 'epic' },
  { min: 0.85, tier: 'rare' },
  { min: 0.70, tier: 'uncommon' },
]

function scoreToRarity(score) {
  for (const { min, tier } of RARITY_THRESHOLDS) {
    if (score >= min) return tier
  }
  return 'common'
}

/**
 * @param {object|null} analysisResult - Full response from compare_faces.v1 or kinship_analyze.v1
 * @param {string} productId - 'familimatch' | 'famililook' — selects rarity label register
 * @returns {{
 *   rewards: Array<{type: string, label: string, value: number, rarity: string, rarityLabel: string}>,
 *   loaded: boolean,
 * }}
 */
export function useVariableReward(analysisResult, productId = 'familimatch') {
  const result = useMemo(() => {
    if (!analysisResult) return { rewards: [], loaded: false }

    const candidates = []

    // Extract feature comparisons (compare_faces.v1)
    if (analysisResult.feature_comparisons) {
      for (const fc of analysisResult.feature_comparisons) {
        if (fc.match) {
          candidates.push({
            type: 'pattern_match',
            label: `Matching ${fc.feature.replace('_', ' ')}`,
            value: 1,
            score: 0.80, // matched features are inherently notable
          })
        }
      }
    }

    // Embedding similarity as a reward candidate
    if (typeof analysisResult.embedding_similarity === 'number') {
      const sim = analysisResult.embedding_similarity
      if (sim >= 0.70) {
        candidates.push({
          type: 'top_percentile',
          label: `Overall similarity: ${Math.round(sim * 100)}%`,
          value: sim,
          score: sim,
        })
      }
    }

    // Feature similarity
    if (typeof analysisResult.feature_similarity === 'number') {
      const fsim = analysisResult.feature_similarity
      if (fsim >= 0.60) {
        candidates.push({
          type: 'rare_stat',
          label: `${Math.round(fsim * 100)}% of features align`,
          value: fsim,
          score: fsim,
        })
      }
    }

    // Percentage as a reward if high
    if (typeof analysisResult.percentage === 'number' && analysisResult.percentage >= 75) {
      candidates.push({
        type: 'top_percentile',
        label: `Top ${100 - analysisResult.percentage}% compatibility`,
        value: analysisResult.percentage / 100,
        score: analysisResult.percentage / 100,
      })
    }

    // Session-scoped deduplication
    let lastType = null
    try {
      if (typeof sessionStorage !== 'undefined') {
        lastType = sessionStorage.getItem(SESSION_KEY)
      }
    } catch { /* noop */ }

    // Filter out previous type (unless only one candidate remains)
    let filtered = candidates.filter(c => c.type !== lastType)
    if (filtered.length === 0) filtered = candidates

    // Sort by score descending, take top 2-3
    filtered.sort((a, b) => b.score - a.score)
    const selected = filtered.slice(0, Math.min(3, Math.max(2, filtered.length)))

    // Map to output shape with rarity
    const labels = RARITY_LABELS[productId] || RARITY_LABELS.familimatch
    const rewards = selected.map(c => {
      const rarity = scoreToRarity(c.score)
      return {
        type: c.type,
        label: c.label,
        value: c.value,
        rarity,
        rarityLabel: labels[rarity] || rarity,
      }
    })

    // Store last type for session dedup
    if (rewards.length > 0) {
      try {
        if (typeof sessionStorage !== 'undefined') {
          sessionStorage.setItem(SESSION_KEY, rewards[0].type)
        }
      } catch { /* noop */ }
    }

    return { rewards, loaded: true }
  }, [analysisResult, productId])

  return result
}
